content:         1→/* =============================================================================
        2→   GLIMWEAVE - Sky Loom Instrument Styles
        3→   Procedural aurora-workshop visual system. No external assets, no URLs.
        4→   ============================================================================= */
        5→
        6→/* ------------------------------------------------------------------------
        7→   CSS Custom Properties & Foundation
        8→   ------------------------------------------------------------------------ */
        9→:root {
       10→  /* Core Colors - Deep Space Aurora */
       11→  --c-space-900: #0a0a1a;
       12→  --c-space-800: #101424;
       13→  --c-space-700: #1a1f3a;
       14→  --c-space-600: #252b50;
       15→  --c-space-500: #333a6b;
       16→
       17→  /* Aurora Spectrum */
       18→  --c-aurora-cyan: #00f2fe;
       19→  --c-aurora-purple: #4f00f5;
       20→  --c-aurora-green: #00ff85;
       21→  --c-aurora-magenta: #ff00e6;
       22→  --c-aurora-gold: #ffd700;
       23→  --c-aurora-blue: #00a2ff;
       24→
       25→  /* Luminance */
       26→  --c-lum-0: #000000;
       27→  --c-lum-10: #1a1a2e;
       28→  --c-lum-20: #16213e;
       29→  --c-lum-30: #0f3460;
       30→  --c-lum-80: #a0a0c0;
       31→  --c-lum-90: #d0d0f0;
       32→  --c-lum-100: #ffffff;
       33→  --c-lum-110: #00f2fe;
       34→
       35→  /* Semantic */
       36→  --c-success: #00ff85;
       37→  --c-warning: #ffd700;
       38→  --c-danger: #ff4757;
       39→  --c-info: #00a2ff;
       40→
       41→  /* Spacing - 4px base grid */
       42→  --s-0: 0;
       43→  --s-1: 0.25rem;
       44→  --s-2: 0.5rem;
       45→  --s-3: 0.75rem;
       46→  --s-4: 1rem;
       47→  --s-5: 1.25rem;
       48→  --s-6: 1.5rem;
       49→  --s-8: 2rem;
       50→  --s-10: 2.5rem;
       51→  --s-12: 3rem;
       52→  --s-16: 4rem;
       53→
       54→  /* Border Radius */
       55→  --r-sm: 0.25rem;
       56→  --r-md: 0.5rem;
       57→  --r-lg: 0.75rem;
       58→  --r-xl: 1.5rem;
       59→  --r-full: 9999px;
       60→
       61→  /* Shadows - Procedural Glow */
       62→  --shadow-glow-cyan: 0 0 8px rgba(0, 242, 254, 0.3), 0 0 16px rgba(0, 242, 254, 0.15);
       63→  --shadow-glow-purple: 0 0 8px rgba(79, 0, 245, 0.3), 0 0 16px rgba(79, 0, 245, 0.15);
       64→  --shadow-glow-green: 0 0 8px rgba(0, 255, 133, 0.3), 0 0 16px rgba(0, 255, 133, 0.15);
       65→  --shadow-glow-gold: 0 0 8px rgba(255, 215, 0, 0.3), 0 0 16px rgba(255, 215, 0, 0.15);
       66→  --shadow-glow-white: 0 0 12px rgba(255, 255, 255, 0.4), 0 0 24px rgba(255, 255, 255, 0.2);
       67→  --shadow-inset: inset 0 1px 0 rgba(255, 255, 255, 0.05), inset 0 -1px 0 rgba(0, 0, 0, 0.3);
       68→
       69→  /* Transitions */
       70→  --t-fast: 100ms ease;
       71→  --t-normal: 200ms ease;
       72→  --t-slow: 400ms ease;
       73→
       74→  /* Font */
       75→  --font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
       76→  --font-mono: "SF Mono", "Monaco", "Inconsolata", "Fira Code", monospace;
       77→
       78→  /* Touch Targets */
       79→  --touch-min: 44px;
       80→}
       81→
       82→/* ------------------------------------------------------------------------
       83→   BASE RESET & HTML SHELL
       84→   ------------------------------------------------------------------------ */
       85→*, *::before, *::after {
       86→  box-sizing: border-box;
       87→  margin: 0;
       88→  padding: 0;
       89→}
       90→
       91→html {
       92→  font-size: 16px;
       93→  scroll-behavior: smooth;
       94→  -webkit-text-size-adjust: 100%;
       95→  text-rendering: optimizeLegibility;
       96→  -webkit-font-smoothing: antialiased;
       97→  -moz-osx-font-smoothing: grayscale;
       98→}
       99→
      100→body {
      101→  min-height: 100vh;
      102→  min-height: 100dvh;
      103→  margin: 0;
      104→  padding: 0;
      105→  background: var(--c-space-900);
      106→  color: var(--c-lum-90);
      107→  font-family: var(--font-family);
      108→  line-height: 1.5;
      109→  overflow-x: hidden;
      110→}
      111→
      112→/* Skip Link - Accessibility */
      113→.skip-link {
      114→  position: absolute;
      115→  top: -100%;
      116→  left: var(--s-4);
      117→  z-index: 1000;
      118→  padding: var(--s-2) var(--s-4);
      119→  background: var(--c-aurora-cyan);
      120→  color: var(--c-space-900);
      121→  font-weight: 600;
      122→  text-decoration: none;
      123→  border-radius: var(--r-sm);
      124→  transition: top var(--t-fast);
      125→}
      126→.skip-link:focus-visible {
      127→  top: var(--s-2);
      128→  outline: 2px solid var(--c-lum-100);
      129→  outline-offset: 2px;
      130→}
      131→
      132→/* Game Shell - The Living Instrument */
      133→#gameShell {
      134→  position: relative;
      135→  width: 100%;
      136→  min-height: 100vh;
      137→  min-height: 100dvh;
      138→  display: flex;
      139→  flex-direction: column;
      140→  background:
      141→    radial-gradient(ellipse at 20% 20%, rgba(0, 242, 254, 0.08) 0%, transparent 50%),
      142→    radial-gradient(ellipse at 80% 10%, rgba(79, 0, 245, 0.08) 0%, transparent 50%),
      143→    radial-gradient(ellipse at 40% 80%, rgba(0, 255, 133, 0.06) 0%, transparent 50%),
      144→    radial-gradient(ellipse at 90% 90%, rgba(255, 0, 230, 0.06) 0%, transparent 50%),
      145→    var(--c-space-900);
      146→  overflow: hidden;
      147→}
      148→
      149→/* Canvas - The Sky Loom */
      150→#gameCanvas {
      151→  position: absolute;
      152→  top: 0;
      153→  left: 0;
      154→  width: 100%;
      155→  height: 100%;
      156→  z-index: 1;
      157→  display: block;
      158→  background:
      159→    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
      160→    repeating-linear-gradient(
      161→      45deg,
      162→      transparent,
      163→      transparent 2px,
      164→      rgba(0, 242, 254, 0.01) 2px,
      165→      rgba(0, 242, 254, 0.01) 4px
      166→    ),
      167→    repeating-linear-gradient(
      168→      -45deg,
      169→      transparent,
      170→      transparent 2px,
      171→      rgba(79, 0, 245, 0.01) 2px,
      172→      rgba(79, 0, 245, 0.01) 4px
      173→    );
      174→}
      175→
      176→/* Phase Atmospheres - Applied to #gameShell via JS */
      177→[data-phase="1"],
      178→#gameShell:not([data-phase]) {
      179→  --phase-primary: var(--c-aurora-cyan);
      180→  --phase-secondary: var(--c-aurora-blue);
      181→  --phase-glow: var(--shadow-glow-cyan);
      182→  --phase-bg-accent: rgba(0, 242, 254, 0.12);
      183→}
      184→
      185→[data-phase="2"] {
      186→  --phase-primary: var(--c-aurora-purple);
      187→  --phase-secondary: var(--c-aurora-magenta);
      188→  --phase-glow: var(--shadow-glow-purple);
      189→  --phase-bg-accent: rgba(79, 0, 245, 0.12);
      190→}
      191→
      192→[data-phase="3"] {
      193→  --phase-primary: var(--c-aurora-green);
      194→  --phase-secondary: var(--c-aurora-gold);
      195→  --phase-glow: var(--shadow-glow-green);
      196→  --phase-bg-accent: rgba(0, 255, 133, 0.12);
      197→}
      198→
      199→[data-phase="4"] {
      200→  --phase-primary: var(--c-lum-100);
      201→  --phase-secondary: var(--c-aurora-cyan);
      202→  --phase-glow: var(--shadow-glow-white);
      203→  --phase-bg-accent: rgba(255, 255, 255, 0.15);
      204→}
      205→
      206→#gameShell[data-phase="1"] #gameCanvas {
      207→  background:
      208→    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
      209→    repeating-linear-gradient(45deg, transparent, transparent 2px, rgba(0, 242, 254, 0.02) 2px, rgba(0, 242, 254, 0.02) 4px);
      210→}
      211→
      212→#gameShell[data-phase="2"] #gameCanvas {
      213→  background:
      214→    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
      215→    repeating-linear-gradient(45deg, transparent, transparent 2px, rgba(79, 0, 245, 0.02) 2px, rgba(79, 0, 245, 0.02) 4px),
      216→    repeating-linear-gradient(-45deg, transparent, transparent 2px, rgba(255, 0, 230, 0.015) 2px, rgba(255, 0, 230, 0.015) 4px);
      217→}
      218→
      219→#gameShell[data-phase="3"] #gameCanvas {
      220→  background:
      221→    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
      222→    repeating-linear-gradient(45deg, transparent, transparent 2px, rgba(0, 255, 133, 0.02) 2px, rgba(0, 255, 133, 0.02) 4px),
      223→    repeating-linear-gradient(-45deg, transparent, transparent 2px, rgba(255, 215, 0, 0.015) 2px, rgba(255, 215, 0, 0.015) 4px);
      224→}
      225→
      226→#gameShell[data-phase="4"] #gameCanvas {
      227→  background:
      228→    radial-gradient(circle at center, rgba(255, 255, 255, 0.05) 0%, transparent 70%),
      229→    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%);
      230→}
      231→
      232→/* ------------------------------------------------------------------------
      233→   UI ROOT & CONTAINER
      234→   ------------------------------------------------------------------------ */
      235→#uiRoot {
      236→  position: relative;
      237→  z-index: 10;
      238→  width: 100%;
      239→  max-width: 1600px;
      240→  margin: 0 auto;
      241→  padding: var(--s-4);
      242→  padding-bottom: calc(var(--s-4) + env(safe-area-inset-bottom, 0px));
      243→}
      244→
      245→#uiRoot:focus-visible {
      246→  outline: none;
      247→}
      248→
      249→.ui-container {
      250→  display: flex;
      251→  flex-direction: column;
      252→  gap: var(--s-4);
      253→  width: 100%;
      254→  height: 100%;
      255→  pointer-events: auto;
      256→}
      257→
      258→/* ------------------------------------------------------------------------
      259→   TOP BAR - Stats Panel
      260→   ------------------------------------------------------------------------ */
      261→.top-bar {
      262→  width: 100%;
      263→  background: rgba(10, 10, 26, 0.7);
      264→  backdrop-filter: blur(4px);
      265→  -webkit-backdrop-filter: blur(4px);
      266→  border: 1px solid rgba(0, 242, 254, 0.2);
      267→  border-radius: var(--r-md);
      268→  padding: var(--s-3);
      269→  box-shadow: var(--shadow-inset);
      270→}
      271→
      272→.stats-panel {
      273→  display: flex;
      274→  flex-wrap: wrap;
      275→  gap: var(--s-4);
      276→  align-items: center;
      277→}
      278→
      279→.stat-row {
      280→  display: flex;
      281→  align-items: baseline;
      282→  gap: var(--s-1);
      283→  font-size: 0.875rem;
      284→}
      285→
      286→.stat-label {
      287→  color: var(--c-lum-60);
      288→  font-weight: 500;
      289→  text-transform: uppercase;
      290→  letter-spacing: 0.05em;
      291→  font-size: 0.75rem;
      292→}
      293→
      294→.stat-value {
      295→  color: var(--phase-primary);
      296→  font-weight: 600;
      297→  font-size: 1rem;
      298→}
      299→
      300→.stat-max {
      301→  color: var(--c-lum-60);
      302→  font-size: 0.875rem;
      303→}
      304→
      305→.stat-bar-container {
      306→  flex: 1;
      307→  min-width: 120px;
      308→  max-width: 300px;
      309→}
      310→
      311→.stat-bar {
      312→  width: 100%;
      313→  height: 8px;
      314→  background: rgba(0, 0, 0, 0.3);
      315→  border-radius: var(--r-full);
      316→  overflow: hidden;
