      324→  border-radius: var(--r-full);
      325→  transition: width var(--t-slow);
      326→  box-shadow: var(--phase-glow);
      327→}
      328→
      329→/* Reservoir bar - special styling */
      330→#reservoirBarFill {
      331→  background: linear-gradient(
      332→    90deg,
      333→    var(--c-aurora-cyan) 0%,
      334→    var(--c-aurora-purple) 50%,
      335→    var(--c-aurora-magenta) 100%
      336→  );
      337→}
      338→
      339→/* Pressure warning on bar */
      340→[data-pressure="high"] .stat-bar-fill,
      341→[data-pressure="critical"] .stat-bar-fill {
      342→  background: linear-gradient(90deg, var(--c-warning), var(--c-danger));
      343→  box-shadow: 0 0 12px rgba(255, 215, 0, 0.5);
      344→}
      345→
      346→/* ------------------------------------------------------------------------
      347→   MAIN PANELS - Asymmetric Desktop Layout
      348→   ------------------------------------------------------------------------ */
      349→.main-panels {
      350→  display: grid;
      351→  grid-template-columns: 280px 1fr;
      352→  gap: var(--s-4);
      353→  flex: 1;
      354→}
      355→
      356→.panel-column {
      357→  display: flex;
      358→  flex-direction: column;
      359→  gap: var(--s-3);
      360→}
      361→
      362→.left-column {
      363→  width: 100%;
      364→}
      365→
      366→.right-column {
      367→  width: 100%;
      368→}
      369→
      370→/* ------------------------------------------------------------------------
      371→   PANELS - Shared Styles
      372→   ------------------------------------------------------------------------ */
      373→.panel {
      374→  background: rgba(16, 20, 36, 0.75);
      375→  backdrop-filter: blur(4px);
      376→  -webkit-backdrop-filter: blur(4px);
      377→  border: 1px solid rgba(0, 242, 254, 0.2);
      378→  border-radius: var(--r-md);
      379→  padding: var(--s-3);
      380→  box-shadow: var(--shadow-inset);
      381→  transition: border-color var(--t-normal), box-shadow var(--t-normal);
      382→}
      383→
      384→.panel:focus-within {
