      387→}
      388→
      389→.panel-header {
      390→  color: var(--phase-primary);
      391→  font-size: 0.875rem;
      392→  font-weight: 600;
      393→  text-transform: uppercase;
      394→  letter-spacing: 0.05em;
      395→  margin-bottom: var(--s-2);
      396→  padding-bottom: var(--s-2);
      397→  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
      398→}
      399→
      400→.panel-desc {
      401→  color: var(--c-lum-60);
      402→  font-size: 0.8125rem;
      403→  margin-bottom: var(--s-3);
      404→  line-height: 1.5;
      405→}
      406→
      407→/* ------------------------------------------------------------------------
      408→   PURCHASE PANEL - Weftlings
      409→   ------------------------------------------------------------------------ */
      410→.purchase-panel {
      411→  min-height: 180px;
      412→}
      413→
      414→.purchase-list {
      415→  display: flex;
      416→  flex-direction: column;
      417→  gap: var(--s-2);
      418→}
      419→
      420→.purchase-item {
      421→  display: flex;
      422→  flex-wrap: wrap;
      423→  align-items: center;
      424→  gap: var(--s-2);
      425→  padding: var(--s-2);
      426→  background: rgba(0, 0, 0, 0.2);
      427→  border-radius: var(--r-sm);
      428→  border: 1px solid transparent;
      429→  transition: background var(--t-fast), border-color var(--t-fast);
