      436→
      437→.purchase-item.disabled {
      438→  opacity: 0.5;
      439→}
      440→
      441→.purchase-item:focus-visible {
      442→  outline: 2px solid var(--phase-primary);
      443→  outline-offset: -2px;
      444→}
      445→
      446→.purchase-name {
      447→  font-weight: 600;
      448→  color: var(--c-lum-100);
