      456→}
      457→
      458→.purchase-cost {
      459→  font-size: 0.75rem;
      460→  color: var(--c-aurora-gold);
      461→  font-weight: 500;
      462→}
      463→
      464→.max-label {
      465→  font-size: 0.6875rem;
      466→  color: var(--c-lum-50);
