      470→
      471→/* ------------------------------------------------------------------------
      472→   UPGRADES PANELS
      473→   ------------------------------------------------------------------------ */
      474→.upgrades-panel,
      475→.doctrine-upgrades-panel,
      476→.permanent-upgrades-panel {
      477→  min-height: 150px;
      478→}
      479→
      480→.upgrade-list {
      481→  display: flex;
      482→  flex-direction: column;
      483→  gap: var(--s-2);
      484→}
      485→
      486→.upgrade-item {
      487→  display: flex;
      488→  flex-wrap: wrap;
      489→  align-items: center;
      490→  gap: var(--s-2);
      491→  padding: var(--s-2);
      492→  background: rgba(0, 0, 0, 0.2);
      493→  border-radius: var(--r-sm);
      494→  transition: background var(--t-fast);
      495→}
      496→
      497→.upgrade-item:hover:not(.disabled) {
      498→  background: rgba(0, 242, 254, 0.05);
