      509→
      510→.upgrade-item:focus-visible {
      511→  outline: 2px solid var(--phase-primary);
      512→  outline-offset: -2px;
      513→}
      514→
      515→.upgrade-name {
      516→  font-weight: 600;
      517→  color: var(--c-lum-100);
      518→}
      519→
      520→.upgrade-desc {
      521→  flex: 1;
      522→  font-size: 0.75rem;
      523→  color: var(--c-lum-60);
      524→}
      525→
      526→.upgrade-cost {
      527→  font-size: 0.75rem;
      528→  color: var(--c-aurora-gold);
      529→  font-weight: 500;
      530→}
      531→
      532→.upgrade-level {
      533→  font-size: 0.6875rem;
      534→  color: var(--c-aurora-cyan);
      535→  font-weight: 500;
      536→}
      537→
      538→.requirement {
      539→  font-size: 0.6875rem;
      540→  color: var(--c-lum-50);
      541→  font-style: italic;
      542→}
      543→
      544→.permanent-upgrades-panel .upgrade-cost {
      545→  color: var(--c-aurora-magenta);
