      547→
      548→/* ------------------------------------------------------------------------
      549→   DOCTRINE PANEL
      550→   ------------------------------------------------------------------------ */
      551→.doctrine-panel {
      552→  min-height: 140px;
      553→}
      554→
      555→.doctrine-list {
      556→  display: flex;
      557→  flex-direction: column;
      558→  gap: var(--s-2);
      559→}
      560→
      561→.doctrine-item {
      562→  display: flex;
      563→  flex-direction: column;
      564→  gap: var(--s-1);
      565→}
      566→
      567→.doctrine-desc {
      568→  font-size: 0.75rem;
      569→  color: var(--c-lum-50);
      570→  padding-left: var(--s-2);
      571→}
      572→
      573→.btn-doctrine {
      574→  width: 100%;
      575→  text-align: left;
      576→  position: relative;
      577→  overflow: hidden;
      578→}
      579→
      580→.btn-doctrine::before {
      581→  content: '';
      582→  position: absolute;
      583→  top: 0;
      584→  left: 0;
      585→  right: 0;
      586→  height: 2px;
      587→  background: linear-gradient(90deg, transparent, var(--phase-primary), transparent);
      588→  opacity: 0;
      589→  transition: opacity var(--t-normal);
      590→}
      591→
      592→.btn-doctrine:hover:not(.disabled):not(.chosen)::before {
      593→  opacity: 1;
      594→}
      595→
      596→.btn-doctrine.chosen {
      597→  background: linear-gradient(135deg, rgba(0, 242, 254, 0.2), rgba(79, 0, 245, 0.2));
      598→  border-color: var(--phase-primary);
      599→  color: var(--c-lum-100);
      600→  cursor: default;
      601→}
      602→
      603→.btn-doctrine.disabled {
      604→  opacity: 0.4;
      605→  cursor: not-allowed;
      606→}
      607→
      608→.no-doctrine {
      609→  color: var(--c-lum-50);
